lf=\"store.historyOpen = false\"\n      @click.self=\"store.historyOpen = false\"\n    >\n      <div class=\"ch-dialog\">\n        <!-- 标题栏 -->\n        <div class=\"ch-header\">\n          <span class=\"ch-title\"><i class=\"fa-solid fa-clock-rotate-left\" /> 历史记录</span>\n          <button class=\"ch-close\" @click=\"store.historyOpen = false\">\n            <i class=\"fa-solid fa-xmark\" />\n          </button>\n        </div>\n\n        <!-- 空状态 -->\n        <div v-if=\"store.configHistory.length === 0\" class=\"ch-empty\">\n          <i class=\"fa-solid fa-inbox\" />\n          <span>暂无历史记录</span>\n        </div>\n\n        <!-- 历史列表 -->\n        <div v-else class=\"ch-list\">\n          <div v-for=\"snap in store.configHistory\" :key=\"snap.id\" class=\"ch-item\">\n            <!-- 缩略预览 -->\n            <div class=\"ch-preview-wrap\">\n              <div class=\"ch-preview\" :class=\"['ub-theme-' + store.settings.theme]\">\n                <BlockRenderer :block=\"snap.config.root\" :is-root=\"true\" />\n              </div>\n            </div>\n\n            <!-- 信息 & 操作 -->\n            <div class=\"ch-info\">\n              <span class=\"ch-snap-title\">{{ snap.title }}</span>\n              <span class=\"ch-snap-time\">{{ formatTime(snap.timestamp) }}</span>\n              <div class=\"ch-actions\">\n                <button class=\"ch-btn ch-btn--primary\" @click=\"rollback(snap.id)\">\n                  <i class=\"fa-solid fa-rotate-left\" /> 回滚\n                </button>\n                <button class=\"ch-btn ch-btn--danger\" @click=\"store.deleteSnapshot(snap.id)\">\n                  <i class=\"fa-solid fa-trash\" />\n                </button>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </transition>\n</template>\n\n<script setup lang=\"ts\">\nimport BlockRenderer from './BlockRenderer.vue';\nimport { useStore } from './store';\n\nconst store = useStore();\n\nfunction formatTime(ts: number): string {\n  const d = new Date(ts);\n  const pad = (n: number) => String(n).padStart(2, '0');\n  return `${pad(d.getMonth() + 1)}/${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`;\n}\n\nfunction rollback(id: string) {\n  store.rollbackTo(id);\n  store.historyOpen = false;\n}\n</script>\n\n<style scoped>\n.ch-overlay {\n  position: fixed;\n  inset: 0;\n  z-index: 100000;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  background: rgba(0, 0, 0, 0.45);\n  backdrop-filter: blur(4px);\n}\n\n.ch-dialog {\n  width: 480px;\n  max-height: min(80vh, calc(100dvh - 24px));\n  display: flex;\n  flex-direction: column;\n  border-radius: 16px;\n  background: var(--ub-bg-solid);\n  border: 1px solid var(--ub-border);\n  box-shadow: 0 24px 64px rgba(0, 0, 0, 0.3);\n}\n\n.ch-header {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 14px 18px;\n  border-bottom: 1px solid var(--ub-border);\n}\n\n.ch-title {\n  font-weight: 600;\n  font-size: 15px;\n  color: var(--ub-text-main);\n  display: flex;\n  align-items: center;\n  gap: 8px;\n}\n\n.ch-close {\n  background: none;\n  border: none;\n  color: var(--ub-text-muted);\n  cursor: pointer;\n  padding: 4px 8px;\n  border-radius: 6px;\n  font-size: 14px;\n  transition: all 0.15s;\n}\n.ch-close:hover {\n  background: var(--ub-hover-bg);\n  color: var(--ub-text-main);\n}\n\n.ch-empty {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  gap: 12px;\n  padding: 48px 0;\n  color: var(--ub-text-muted);\n  font-size: 14px;\n}\n.ch-empty i {\n  font-size: 32px;\n  opacity: 0.4;\n}\n\n.ch-list {\n  flex: 1;\n  min-height: 0;\n  overflow-y: auto;\n  padding: 12px;\n  display: flex;\n  flex-direction: column;\n  gap: 12px;\n}\n\n.ch-item {\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n  padding: 10px;\n  border-radius: 12px;\n  border: 1px solid var(--ub-border);\n  background: var(--ub-bg-glass);\n  transition: border-color 0.15s;\n}\n.ch-item:hover {\n  border-color: var(--ub-accent);\n}\n\n.ch-preview-wrap {\n  width: 100%;\n  height: 120px;\n  flex-shrink: 0;\n  border-radius: 8px;\n  overflow: hidden;\n  border: 1px solid var(--ub-border-light);\n  position: relative;\n}\n\n.ch-preview {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 300%;\n  height: 360px;\n  transform: scale(0.333);\n  transform-origin: top left;\n  pointer-events: none;\n  overflow: hidden;\n}\n\n.ch-info {\n  flex: 1;\n  min-width: 0;\n  display: flex;\n  flex-direction: column;\n  gap: 4px;\n}\n\n.ch-snap-title {\n  font-weight: 600;\n  font-size: 13px;\n  color: var(--ub-text-main);\n  overflow: hidden;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n}\n\n.ch-snap-time {\n  font-size: 11px;\n  color: var(--ub-text-muted);\n}\n\n.ch-actions {\n  margin-top: auto;\n  display: flex;\n  gap: 6px;\n}\n\n.ch-btn {\n  padding: 4px 10px;\n  border: none;\n  border-radius: 6px;\n  font-size: 12px;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  gap: 4px;\n  transition: all 0.15s;\n}\n\n.ch-btn--primary {\n  background: var(--ub-accent);\n  color: #fff;\n}\n.ch-btn--primary:hover {\n  filter: brightness(1.1);\n}\n\n.ch-btn--danger {\n  background: transparent;\n  color: var(--ub-text-muted);\n  border: 1px solid var(--ub-border);\n}\n.ch-btn--danger:hover {\n  background: rgba(220, 60, 60, 0.15);\n  color: #dc3c3c;\n  border-color: rgba(220, 60, 60, 0.3);\n}\n\n@media (pointer: coarse) {\n  .ch-close {\n    min-width: 36px;\n    min-height: 36px;\n  }\n\n  .ch-btn {\n    min-height: 36px;\n    padding: 6px 12px;\n    font-size: 13px;\n  }\n}\n\n@media (max-width: 768px) {\n  .ch-dialog {\n    width: calc(100vw - 16px);\n    max-height: calc(100dvh - 16px);\n    border-radius: 12px;\n  }\n\n  .ch-header {\n    padding: 12px 14px;\n  }\n\n  .ch-list {\n    padding: 10px;\n  }\n\n  .ch-preview-wrap {\n    height: 96px;\n  }\n\n  .ch-actions {\n    flex-wrap: wrap;\n  }\n}\n\n/* 弹窗动画 */\n.ch-fade-enter-active,\n.ch-fade-leave-active {\n  transition: opacity 0.2s ease;\n}\n.ch-fade-enter-active .ch-dialog,\n.ch-fade-leave-active .ch-dialog {\n  transition: transform 0.2s ease;\n}\n.ch-fade-enter-from,\n.ch-fade-leave-to {\n  opacity: 0;\n}\n.ch-fade-enter-from .ch-dialog {\n  transform: scale(0.95) translateY(10px);\n}\n.ch-fade-leave-to .ch-dialog {\n  transform: scale(0.95) translateY(10px);\n}\n</style>\n"],"sourceRoot":""}]);
