;\n  height: 100%;\n  min-width: 0;\n  background: var(--ub-shadow); /* 稍微深一点的背景区分工作区 */\n}\n\n.control-area__toolbar {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  padding: 8px 12px;\n  background: var(--ub-bg-glass);\n  border-bottom: 1px solid var(--ub-border);\n  flex-wrap: wrap;\n}\n\n.control-area__tool-btn {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  width: 30px;\n  height: 30px;\n  border: none;\n  background: var(--ub-border);\n  color: var(--ub-text-muted);\n  border-radius: 6px;\n  font-size: 13px;\n  cursor: pointer;\n  transition:\n    background 0.15s,\n    color 0.15s;\n  touch-action: manipulation;\n}\n\n.control-area__tool-btn:hover {\n  background: var(--ub-bg-hover);\n  color: var(--ub-text-main);\n}\n\n.control-area__tool-btn--active {\n  background: var(--ub-accent-bg) !important;\n  color: var(--ub-accent-text) !important;\n}\n\n.control-area__title {\n  margin-left: auto;\n  font-size: 13px;\n  font-weight: 600;\n  color: var(--ub-text-secondary);\n  letter-spacing: 0.5px;\n}\n\n.control-area__dynamic-root {\n  flex: 1;\n  overflow-y: auto;\n  padding: 16px; /* 给动态内容充足的边距 */\n  display: flex;\n  flex-direction: column;\n  overscroll-behavior: contain;\n}\n\n@media (pointer: coarse) {\n  .control-area__tool-btn {\n    width: 36px;\n    height: 36px;\n    font-size: 14px;\n  }\n}\n\n@media (max-width: 768px) {\n  .control-area__title {\n    width: 100%;\n    margin-left: 0;\n    text-align: left;\n  }\n\n  .control-area__dynamic-root {\n    padding: 12px;\n  }\n}\n</style>\n"],"sourceRoot":""}]);
